"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[264],{28653:e=>{e.exports=JSON.parse('{"functions":[{"name":"InitServer","desc":"Injects the `SOUNDS Configuration` into the library and creates the `Schema`.\\n\\n:::info\\n- It compiles all the information into `Folders`, `Configurations`,  `Sounds`, `SoundGroups`, and sounds names to `Preload`.\\n- The schema is locked once `Start.InitServer` runs. Meaning you cannot add new `Sounds`, `SoundGroups`, etc... to the library.\\n:::\\n\\n:::danger\\nThis should only run once!\\n:::\\n\\n```lua\\nlocal ReplicatedStorage = game:GetService(\\"ReplicatedStorage\\")\\nlocal ServerStorage = game:GetService(\\"ServerStorage\\")\\n\\nlocal VluxySF = require(ReplicatedStorage.VluxySF)\\n\\nlocal soundConfig = ServerStorage:FindFirstChild(\\"SOUNDS\\")\\n\\nVluxySF.Startup.InitServer(soundConfig)\\n```","params":[{"name":"soundFolder","desc":"The `SOUNDS Configurartion`.","lua_type":"Configuration"}],"returns":[],"function_type":"static","realm":["Server"],"source":{"line":398,"path":"lib/init.luau"}},{"name":"InitClient","desc":"Fetches the `Schema` from the server and preloads all sounds that require it.\\n\\n:::danger\\nThis should only run once!\\n:::\\n\\n```lua\\nlocal ReplicatedStorage = game:GetService(\\"ReplicatedStorage\\")\\n\\nlocal VluxySF = require(ReplicatedStorage.VluxySF)\\n\\nlocal timeout = 4\\n\\nVluxySF.Startup.InitClient(timeout)\\n```","params":[{"name":"timeout","desc":"Timeout for waiting on sounds to preload.","lua_type":"number?"}],"returns":[],"function_type":"static","realm":["Client"],"yields":true,"source":{"line":435,"path":"lib/init.luau"}},{"name":"IsInitialized","desc":"Checks if the sound schema has been initialized.\\n\\n```lua\\nprint(VluxySF.Startup.IsInitialized())\\n```","params":[],"returns":[{"desc":"Is initialized?","lua_type":"boolean"}],"function_type":"static","source":{"line":460,"path":"lib/init.luau"}},{"name":"WaitForSchema","desc":" \\n\\n\\nWaits until the sound schema is initialized and ready for use.\\n\\n:::info\\nIf you know that your code will execute after the `Schema` is loaded then this is not needed.\\n:::\\n\\n```lua\\nlocal ReplicatedStorage = game:GetService(\\"ReplicatedStorage\\")\\n\\nlocal VluxySF = require(ReplicatedStorage.VluxySF)\\n\\nVluxySF.Startup.WaitForSchema() --yields\\n\\nVluxySF.FetchPlayOnce(\\"MySound\\")\\n```","params":[],"returns":[],"function_type":"static","yields":true,"source":{"line":485,"path":"lib/init.luau"}},{"name":"ConnectForSchema","desc":"Alternative to `Startup.WaitForSchema` if you do not want to pause the current block.\\n\\n```lua\\nlocal ReplicatedStorage = game:GetService(\\"ReplicatedStorage\\")\\n\\nlocal VluxySF = require(ReplicatedStorage.VluxySF)\\n\\nVluxySF.Startup.ConnectForSchema(function()\\n\\tVluxySF.FetchPlayOnce(\\"MySound\\")\\nend)\\n\\n--doesn\'t yield down here!\\n```","params":[{"name":"finished","desc":"Callback function to execute when the schema is created.","lua_type":"() -> ()"}],"returns":[{"desc":"Cleanup function.","lua_type":"() -> ()"}],"function_type":"static","source":{"line":514,"path":"lib/init.luau"}}],"properties":[],"types":[],"name":"Startup","desc":"Functions for initializing the library and making sure its safe to use the `Schema`.\\n\\n:::warning\\nSome functions in this library cannot run until you wait for the schema to be initialized.\\n:::","source":{"line":367,"path":"lib/init.luau"}}')}}]);